import pandas as pd

def check_completeness(df: pd.DataFrame, required_cols: list[str]) -> dict:
    results = {}
    total_rows = len(df)

    for col in required_cols:
        non_null_count = df[col].notna().sum()
        completeness_pct = (non_null_count / total_rows) * 100
        results[col] = {
            "non_null_count": int(non_null_count),
            "null_count": int(total_rows - non_null_count),
            "completeness_pct": round(completeness_pct, 2),
            "passed": completeness_pct >= 99.0  # define your threshold
        }

    return results

# Example usage
df = pd.DataFrame({
    "user_id":  [1, 2, None, 4, 5],
    "email":    ["a@b.com", None, "c@d.com", None, "e@f.com"],
    "signup_date": ["2024-01-01", "2024-01-02", "2024-01-03", None, "2024-01-05"]
})

report = check_completeness(df, ["user_id", "email", "signup_date"])
for col, stats in report.items():
    print(f"{col}: {stats['completeness_pct']}% complete — {'✅ PASS' if stats['passed'] else '❌ FAIL'}")

def check_row_count(df: pd.DataFrame, expected_min: int, expected_max: int) -> dict:
    actual = len(df)
    return {
        "actual_rows": actual,
        "expected_min": expected_min,
        "expected_max": expected_max,
        "passed": expected_min <= actual <= expected_max
    }

from pydantic import BaseModel, EmailStr, validator, Field
from typing import Optional, Literal
from datetime import date

class UserRecord(BaseModel):
    user_id: int
    email: EmailStr
    age: int = Field(ge=0, le=120)
    status: Literal["pending", "active", "cancelled", "completed"]
    score: float = Field(ge=0.0, le=100.0)
    signup_date: date

    @validator("email")
    def email_must_be_lowercase(cls, v):
        return v.lower()

def validate_records(records: list[dict]) -> tuple[list, list]:
    valid, invalid = [], []
    for record in records:
        try:
            valid.append(UserRecord(**record).dict())
        except Exception as e:
            invalid.append({"record": record, "error": str(e)})
    return valid, invalid
